// ── Helpers ──

/** Convert a JS object of key:value pairs to a minified line like key1:'val1',key2:'val2' */
function toMinifiedLine(obj) {
  return Object.entries(obj)
    .map(([k, v]) => {
      // Escape single quotes inside values
      const escaped = String(v).replace(/'/g, "\\'");
      return `${k}:'${escaped}'`;
    })
    .join(',');
}

// ── Main ──

const src = fs.readFileSync(FILE, 'utf8');
const lines = src.split('\n');

// Language order as they appear in the file
const langOrder = ['es','en','pt','fr','de','it','ja','zh','ru','id','ar','ko','th','vi'];

// Find the line ranges for each language block.
// We'll search for the pattern that starts or continues each lang block.
// Strategy: find the last content line of each language block (the line just before the block-ending pattern).
// The block ends with either:
//   },nextLang:{   (on same line as closing brace)
//   },\n           (closing brace on its own line)
//   };             (last language, end of object)

// Build a map: langCode → line number of the LAST content line of that block
// We insert new keys as a new line AFTER the last content line and BEFORE the closing brace.

// For each language, find:
// 1. The opening line (e.g. "const T={es:{" or "en:{" or ",ar:{")
// 2. The closing pattern

const langStartLines = {};
const langEndLines = {};

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  for (const lang of langOrder) {
    // Match opening: "const T={es:{" or "},en:{" or "\nfr:{" or ",ar:{"
    const openers = [
      `{${lang}:{`,
      `${lang}:{`,
    ];
    for (const opener of openers) {
      if (line.includes(opener) && !langStartLines[lang]) {
        langStartLines[lang] = i;
        break;
      }
    }
  }
}

// Sort languages by their start line
const sortedLangs = langOrder.slice().sort((a, b) => langStartLines[a] - langStartLines[b]);

// For each language, the end is the line just before the next language's start, or the end of the object
for (let idx = 0; idx < sortedLangs.length; idx++) {
  const lang = sortedLangs[idx];
  if (idx < sortedLangs.length - 1) {
    const nextLang = sortedLangs[idx + 1];
    const nextStart = langStartLines[nextLang];
    // The end line is the line that contains "}," before the next lang start
    // It could be on the same line as nextStart (e.g. "},en:{") or the line before
    if (lines[nextStart].match(/^\s*},/)) {
      // The closing brace is on the same line as next lang opens (e.g. "},en:{")
      // OR it's a standalone "}," line and next lang is on next line
      langEndLines[lang] = nextStart;
    } else if (lines[nextStart].match(/^\s*,\w+:\{/) || lines[nextStart].match(/^\s*\w+:\{/)) {
      // Next lang starts on its own line, closing brace is on previous line
      langEndLines[lang] = nextStart - 1;
    } else {
      langEndLines[lang] = nextStart;
    }
  } else {
    // Last language - find the closing "}" of this lang block (NOT the "};" of the T object).
    // The structure is: ...content\n}\n};\n\nexport default T;
    // We need the "}" line that closes the lang block, which is the line BEFORE "};"
    for (let i = lines.length - 1; i >= langStartLines[lang]; i--) {
      if (lines[i].trim() === '};') {
        // The line before "};" should be "}" which closes the last lang block
        if (i > 0 && lines[i - 1].trim() === '}') {
          langEndLines[lang] = i - 1; // point to the "}" that closes the lang block
        } else {
          langEndLines[lang] = i; // fallback
        }
        break;
      }
    }
  }
}

console.log('Language block boundaries:');
for (const lang of sortedLangs) {
  console.log(`  ${lang}: lines ${langStartLines[lang] + 1}-${langEndLines[lang] + 1}`);
}

// Now inject. We process from BOTTOM to TOP so line numbers don't shift.
const insertions = []; // [{lineIndex, text}]

for (const lang of sortedLangs) {
  if (!newKeys[lang]) {
    console.warn(`WARNING: No translations defined for language "${lang}". Skipping.`);
    continue;
  }

  const endLineIdx = langEndLines[lang];
  const endLine = lines[endLineIdx];
  const newContent = toMinifiedLine(newKeys[lang]);

  // We need to insert the new keys line just before the closing of this block.
  // The end line could be:
  // Case A: "},en:{" — the closing brace and next opener are on the same line
  // Case B: "}," or "};" — standalone closing
  // Case C: the last content line ends with comma, and the next line has the closing

  if (endLine.match(/^\s*},\w+:\{/)) {
    // Case A: "},en:{" — insert a new line BEFORE this line with trailing comma
    // But we also need to ensure the previous line ends with a comma
    const prevLineIdx = endLineIdx - 1;
    let prevLine = lines[prevLineIdx];
    if (!prevLine.trimEnd().endsWith(',')) {
      lines[prevLineIdx] = prevLine + ',';
    }
    insertions.push({ lineIndex: endLineIdx, text: newContent + ',' });
  } else if (endLine.match(/^\s*\}[,;]?\s*$/)) {
    // Case B: standalone "}," or "};" or "}"
    const prevLineIdx = endLineIdx - 1;
    let prevLine = lines[prevLineIdx];
    if (!prevLine.trimEnd().endsWith(',')) {
      lines[prevLineIdx] = prevLine + ',';
    }
    insertions.push({ lineIndex: endLineIdx, text: newContent });
  } else if (endLine.match(/^\s*\};/)) {
    // Case: end of file "};"
    const prevLineIdx = endLineIdx - 1;
    let prevLine = lines[prevLineIdx];
    if (!prevLine.trimEnd().endsWith(',')) {
      lines[prevLineIdx] = prevLine + ',';
    }
    insertions.push({ lineIndex: endLineIdx, text: newContent });
  } else {
    // The end line itself IS a content line — just append after it
    // Make sure current line ends with comma
    if (!endLine.trimEnd().endsWith(',')) {
      lines[endLineIdx] = endLine + ',';
    }
    insertions.push({ lineIndex: endLineIdx + 1, text: newContent });
  }
}

// Sort insertions by lineIndex descending so we can splice without shifting
insertions.sort((a, b) => b.lineIndex - a.lineIndex);

for (const ins of insertions) {
  lines.splice(ins.lineIndex, 0, ins.text);
}

fs.writeFileSync(FILE, lines.join('\n'), 'utf8');

// Verify
const result = fs.readFileSync(FILE, 'utf8');
const keyCount = (result.match(/wel_title:/g) || []).length;
console.log(`\nDone! "wel_title" found in ${keyCount} language blocks (expected 14).`);
const finDepCount = (result.match(/fin_depreciation:/g) || []).length;
console.log(`"fin_depreciation" found in ${finDepCount} language blocks (expected 14).`);
const totalLines = result.split('\n').length;
console.log(`Total lines: ${totalLines} (was ${src.split('\n').length})`);
